#!/usr/bin/env python3
"""make-ocr-test-image.py — render known text to a high-contrast PNG for ocr-probe.

Produces a clean black-on-white image containing a known string so the OCR
admission gate (`ocr-probe`) can check that the model's decoded output OVERLAPS
the rendered text (looser gate: token/word overlap, not exact match).

Usage:
  python3 make-ocr-test-image.py /tmp/ocr_hello.png --text "HELLO WORLD 2026"
  python3 make-ocr-test-image.py /tmp/ocr_hello.png            # default text
"""
from __future__ import annotations

import argparse
import sys
from pathlib import Path


# Candidate fonts (macOS + common Linux). First that loads wins.
_FONT_CANDIDATES = [
    "/System/Library/Fonts/Supplemental/Arial Bold.ttf",
    "/System/Library/Fonts/Supplemental/Arial.ttf",
    "/Library/Fonts/Arial.ttf",
    "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
    "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf",
]


def main() -> None:
    ap = argparse.ArgumentParser()
    ap.add_argument("output", type=Path)
    ap.add_argument("--text", default="HELLO WORLD 2026",
                    help="text to render (the OCR gate checks for this)")
    ap.add_argument("--size", type=int, default=448,
                    help="square image side (rounded to a multiple of 28)")
    args = ap.parse_args()

    try:
        from PIL import Image, ImageDraw, ImageFont
    except ImportError:
        print("ERROR: Pillow required: pip install pillow", file=sys.stderr)
        sys.exit(1)

    unit = 28  # patch(14) * merge(2)
    side = max(unit, (args.size // unit) * unit)

    img = Image.new("RGB", (side, side), color=(255, 255, 255))
    draw = ImageDraw.Draw(img)

    # Load a bold TTF; fall back to PIL's bitmap default (small but readable).
    font = None
    px = max(28, side // 9)
    for path in _FONT_CANDIDATES:
        try:
            font = ImageFont.truetype(path, px)
            break
        except OSError:
            continue
    if font is None:
        font = ImageFont.load_default()
        print("[make-ocr] WARNING: no TTF found, using bitmap default font",
              file=sys.stderr)

    # Wrap the text onto up to 3 lines so big strings fit the square.
    words = args.text.split()
    lines: list[str] = []
    if len(words) <= 2:
        lines = [args.text]
    else:
        mid = (len(words) + 1) // 2
        lines = [" ".join(words[:mid]), " ".join(words[mid:])]

    # Vertically center the block.
    line_h = px + px // 4
    total_h = line_h * len(lines)
    y = (side - total_h) // 2
    for line in lines:
        bbox = draw.textbbox((0, 0), line, font=font)
        w = bbox[2] - bbox[0]
        x = (side - w) // 2
        draw.text((x, y), line, fill=(0, 0, 0), font=font)
        y += line_h

    args.output.parent.mkdir(parents=True, exist_ok=True)
    img.save(args.output)
    print(f"[make-ocr] wrote {args.output} ({side}x{side}) text={args.text!r}",
          file=sys.stderr)


if __name__ == "__main__":
    main()
